import React, { useCallback, useEffect, useState } from 'react';
import AddProjectModal from './AddProjectModal';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Sidebar = () => {
  const [isModalOpen, setModalState] = useState(false);
  const [projects, setProjects] = useState([]);
  const [paramsWindow, setParamsWindow] = useState(window.location.pathname.slice(1));

  useEffect(() => {
    projectData();
    document.addEventListener('projectUpdate', ({ detail }) => {
      projectData();
    });
    return () => {
      document.removeEventListener('projectUpdate', {}, false);
    };
  }, []);

  const handleLocation = (e) => {
    setParamsWindow(new URL(e.currentTarget.href).pathname.slice(1));
  };

  const openModal = useCallback(() => {
    setModalState(true);
  }, []);

  const closeModal = useCallback(() => {
    setModalState(false);
  }, []);

  const projectData = () => {
    axios.get('http://localhost:9000/projects/')
      .then((res) => {
        setProjects(res.data);
      });
  };

  return (
    <div className="sidebar flex flex-col min-h-screen">
      {/* Sidebar Header */}
      <div className="sidebar-header flex items-center justify-between">
        <span className="text-lg font-semibold">Projects</span>
        <button onClick={openModal} className="add-project-btn">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5">
            <path fillRule="evenodd" d="M12 5.25a.75.75 0 01.75.75v5.25H18a.75.75 0 010 1.5h-5.25V18a.75.75 0 01-1.5 0v-5.25H6a.75.75 0 010-1.5h5.25V6a.75.75 0 01.75-.75z" clipRule="evenodd" />
          </svg>
        </button>
      </div>

      {/* Project List */}
      <ul className="overflow-y-auto flex-1">
        {projects.map((project, index) => (
          <Link key={index} to={project._id} onClick={(e) => handleLocation(e)}>
            <li className={`px-5 py-2 mb-1 transition-all rounded-lg 
              ${paramsWindow === project._id ? 'bg-indigo-500 text-white font-medium' : 'text-gray-300 hover:bg-gray-700 hover:text-white'}`}>
              {project.title}
            </li>
          </Link>
        ))}
      </ul>

      <AddProjectModal isModalOpen={isModalOpen} closeModal={closeModal} />
    </div>
  );
};

export default Sidebar;
